function parseSemVer(versionStr) {
  // Strip build metadata for comparison purposes only
  const [withoutBuild] = versionStr.split('+');
  const [corePart, ...preParts] = withoutBuild.split('-');
  const preRelease = preParts.join('-');
  const [major, minor, patch] = corePart.split('.').map(Number);
  return { major, minor, patch, preRelease };
}

function comparePreRelease(a, b) {
  // No pre-release means release version — higher precedence
  if (a === '' && b === '') return 0;
  if (a === '') return 1;
  if (b === '') return -1;

  const aIds = a.split('.');
  const bIds = b.split('.');
  const len = Math.min(aIds.length, bIds.length);

  for (let i = 0; i < len; i++) {
    const aId = aIds[i];
    const bId = bIds[i];
    const aIsNum = /^\d+$/.test(aId);
    const bIsNum = /^\d+$/.test(bId);

    if (aIsNum && bIsNum) {
      const diff = Number(aId) - Number(bId);
      if (diff !== 0) return diff;
    } else if (aIsNum !== bIsNum) {
      // Numeric identifiers have lower precedence than alphanumeric
      return aIsNum ? -1 : 1;
    } else {
      if (aId < bId) return -1;
      if (aId > bId) return 1;
    }
  }

  // All shared identifiers equal — larger set has higher precedence
  return aIds.length - bIds.length;
}

function compareSemVer(a, b) {
  const pa = parseSemVer(a);
  const pb = parseSemVer(b);

  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;

  return comparePreRelease(pa.preRelease, pb.preRelease);
}

function sortVersions(versions) {
  return versions.slice().sort(compareSemVer);
}

